        newNode.next = after;
        newNode.prev  = before;
        after.prev = newNode;

        this.length++;
        return true;
    }

    remove(index) {
        if(index < 0 || index >= this.length) return undefined;
        if(index === 0) return this.shift();
        if(index === this.length-1) return this.pop();

        const temp = this.get(index);
        temp.prev.next = temp.next;
        temp.next.prev = temp.prev;

