        if(this.length <=1) return;
        let current = this.head;
        let prev = null;

        while(current !== null) {
            prev = current.prev;
            current.prev = current.next;
            current.next = prev;
            current = current.prev;
        }

        prev = this.head;
        this.head = this.tail;
        this.tail = prev;  

        return this;
    }

